{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyPxwvoH9mRX9o7Qaok1d23i"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","execution_count":1,"metadata":{"id":"rVZvWJ-tWPQW","executionInfo":{"status":"ok","timestamp":1773122703703,"user_tz":-180,"elapsed":40,"user":{"displayName":"Bassem Amin","userId":"03844483762484690298"}}},"outputs":[],"source":["\"\"\"\n","streaming_service.py\n","---------------------\n","Defines the StreamingService class that controls content access\n","based on user subscription and content availability.\n","\n","Author: [Your Name]\n","Date: [Submission Date]\n","\"\"\"\n","\n","\n","class StreamingService:\n","    \"\"\"\n","    Manages the streaming logic — checks subscription eligibility\n","    and content availability before granting access.\n","\n","    Attributes:\n","        __user (User): The user requesting the stream.\n","        __subscription (Subscription): The user's active subscription.\n","    \"\"\"\n","\n","    def __init__(self, user, subscription):\n","        \"\"\"\n","        Initialise the StreamingService for a user/subscription pair.\n","\n","        Args:\n","            user (User): The streaming user.\n","            subscription (Subscription): The user's subscription.\n","        \"\"\"\n","        self.__user = user\n","        self.__subscription = subscription\n","\n","    def can_access(self, content) -> bool:\n","        \"\"\"\n","        Determine whether the user can access the given content.\n","\n","        Access rules:\n","            - Subscription must be active.\n","            - Content must be available.\n","            - Non-premium content: accessible by any active subscription.\n","            - Premium content: requires access level >= 3 (Premium plan).\n","\n","        Args:\n","            content (Content): The content to check.\n","\n","        Returns:\n","            bool: True if the user can access the content.\n","        \"\"\"\n","        if not self.__subscription.is_active():\n","            return False\n","        if not content.is_available():\n","            return False\n","        if content.is_premium():\n","            return self.__subscription.get_plan().get_access_level() >= 3\n","        return True\n","\n","    def stream_content(self, content) -> str:\n","        \"\"\"\n","        Attempt to stream the content for the user.\n","\n","        Args:\n","            content (Content): The content to stream.\n","\n","        Returns:\n","            str: A message indicating success or the reason for denial.\n","        \"\"\"\n","        if not self.__subscription.is_active():\n","            return (f\"Access Denied: {self.__user.get_name()}'s subscription \"\n","                    f\"is not active. Please renew your subscription.\")\n","        if not content.is_available():\n","            return (f\"Access Denied: '{content.get_title()}' is currently \"\n","                    f\"unavailable for streaming.\")\n","        if content.is_premium() and self.__subscription.get_plan().get_access_level() < 3:\n","            return (f\"Access Denied: '{content.get_title()}' is premium content. \"\n","                    f\"Please upgrade to Premium plan to access this content.\")\n","        return (f\"Now streaming '{content.get_title()}' for \"\n","                f\"{self.__user.get_name()}. Enjoy watching!\")\n","\n","    def __str__(self) -> str:\n","        \"\"\"Return a string representation.\"\"\"\n","        return (f\"StreamingService | User: {self.__user.get_name()} | \"\n","                f\"Plan: {self.__subscription.get_plan().get_plan_name()} | \"\n","                f\"Active: {self.__subscription.is_active()}\")"]}]}